function i(t){const e=t.replace(/\D/g,"");return e.length!==10?t:`(${e.slice(0,3)}) ${e.slice(3,6)}-${e.slice(6)}`}function n(t){const e=t.replace(/\D/g,"");return e.length!==10?"(***) ***-****":`(***) ***-${e.slice(6)}`}function r(t){return t.replace(/\D/g,"").padStart(5,"0").slice(0,5)}function c(t){return r(t).slice(0,3)}function s(t){return`$${Number(t).toFixed(2)}`}export{i as a,s as f,c as g,n as m};
